{action_set_definitions}: {
  "fetch_property_state": {
    "description": "Retrieves the current metadata, physical attributes, and market context for a specific property from the environment state.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string",
          "description": "The unique identifier of the property (e.g., 'PROP-9921')."
        }
      },
      "required": [
        "property_id"
      ]
    },
    "example_output": {
      "property_id": "PROP-9921",
      "physical_attributes": "15,000 sqft Office Space",
      "property_condition": "Good",
      "market_context": "CBD Core, 5% vacancy",
      "current_valuation_model": "Sales Comparison"
    }
  },
  "fetch_financial_data": {
    "description": "Queries the environment for financial records including rent rolls and operating expense histories required for cash flow modeling.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string",
          "description": "The unique identifier of the property."
        },
        "data_type": {
          "type": "string",
          "enum": [
            "RENT_ROLL",
            "OPERATING_EXPENSES",
            "TAX_RECORDS"
          ],
          "description": "The type of financial data to retrieve."
        }
      },
      "required": [
        "property_id",
        "data_type"
      ]
    },
    "example_output": {
      "records": [
        {
          "unit": "101",
          "tenant": "TechCorp",
          "rent_sqft": 45.0,
          "lease_expiry": "2025-12-31"
        }
      ]
    }
  },
  "update_valuation_parameters": {
    "description": "Configures the core Discounted Cash Flow (DCF) parameters including duration and rates.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string"
        },
        "term_years": {
          "type": "integer",
          "description": "Duration of the holding period (e.g., 10)."
        },
        "discount_rate": {
          "type": "number",
          "description": "The annual discount rate as a decimal (e.g., 0.09)."
        },
        "reversionary_cap_rate": {
          "type": "number",
          "description": "The exit/terminal cap rate as a decimal (e.g., 0.065)."
        }
      },
      "required": [
        "property_id",
        "term_years",
        "discount_rate",
        "reversionary_cap_rate"
      ]
    },
    "example_output": {
      "status": "success",
      "message": "DCF parameters updated."
    }
  },
  "apply_market_leasing_assumptions": {
    "description": "Sets the Market Leasing Assumptions (MLA) for turnover and renewal scenarios.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string"
        },
        "renewal_probability": {
          "type": "number",
          "description": "Probability of existing tenants renewing (e.g., 0.70)."
        },
        "downtime_months": {
          "type": "integer",
          "description": "Expected months of vacancy between leases (e.g., 9)."
        }
      },
      "required": [
        "property_id",
        "renewal_probability",
        "downtime_months"
      ]
    },
    "example_output": {
      "status": "success"
    }
  },
  "configure_expense_recoveries": {
    "description": "Sets the recovery logic for operating expenses, specifically the gross-up percentage.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string"
        },
        "gross_up_percentage": {
          "type": "number",
          "description": "Percentage to gross up variable expenses for recovery calculations (e.g., 1.0 for 100%)."
        }
      },
      "required": [
        "property_id",
        "gross_up_percentage"
      ]
    },
    "example_output": {
      "status": "success"
    }
  },
  "calculate_valuation_npv": {
    "description": "Executes the valuation engine based on currently configured parameters and returns the final NPV.",
    "parameters": {
      "type": "object",
      "properties": {
        "property_id": {
          "type": "string"
        }
      },
      "required": [
        "property_id"
      ]
    },
    "example_output": {
      "npv": 24500000.5,
      "currency": "USD",
      "calculation_date": "2023-10-27"
    }
  }
}
